const initialState = { 
    cities: [],
    auxiliar: [],
    city: []
}

const citiesReducers = (state = initialState, action) => {
    switch(action.type) {
        case 'GETCITIES':
            return {
                ...state,
                cities: action.payload,
                auxiliar: action.payload
            }
        case 'GETONECITY':
            return{
                ...state,
                cities: action.payload,
                auxiliar: action.payload
            }
        default:
            return state
    }
}
export default citiesReducers
